1	package cmd
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"strings"
7	
8		ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
9		"github.com/DocumentDrivenDX/ddx/internal/serverreg"
10		"github.com/spf13/cobra"
11	)
12	
13	func (f *CommandFactory) newArtifactCommand() *cobra.Command {
14		cmd := &cobra.Command{
15			Use:     "artifact",
16			Aliases: []string{"artifacts"},
17			Short:   "Inspect and regenerate DDx artifacts",
18			Long: `Inspect and regenerate graph artifacts.
19	
20	Regeneration is an explicit wrapper around the FEAT-010 execution substrate:
21	DDx selects a generator definition for the artifact, records the run, and marks
22	the record with produces_artifact. DDx does not synthesize manual fallback
23	prompts when an artifact has no generator provenance.`,
24			PersistentPreRunE: func(cmd *cobra.Command, args []string) error {
25				serverreg.TryRegisterAsync(f.WorkingDir)
26				return nil
27			},
28			Run: func(cmd *cobra.Command, args []string) {
29				_ = cmd.Help()
30			},
31		}
32	
33		cmd.AddCommand(f.newArtifactRegenerateCommand())
34		return cmd
35	}
36	
37	func (f *CommandFactory) newArtifactRegenerateCommand() *cobra.Command {
38		cmd := &cobra.Command{
39			Use:   "regenerate <artifact-id>",
40			Short: "Regenerate one artifact through its execution definition",
41			Args:  cobra.ExactArgs(1),
42			RunE: func(cmd *cobra.Command, args []string) error {
43				artifactID := strings.TrimSpace(args[0])
44				definitionID, _ := cmd.Flags().GetString("definition")
45	
46				graph, err := f.buildDocGraph()
47				if err != nil {
48					return err
49				}
50				if _, ok := graph.Show(artifactID); !ok {
51					return fmt.Errorf("artifact %q not found in document graph", artifactID)
52				}
53	
54				store := f.execStore()
55				defID, err := selectArtifactGenerator(store, artifactID, definitionID)
56				if err != nil {
57					return err
58				}
59	
60				rec, err := store.RunWithOptions(cmd.Context(), defID, ddxexec.RunOptions{
61					ProducesArtifact: artifactID,
62				})
63				if err != nil {
64					return err
65				}
66	
67				if asJSON, _ := cmd.Flags().GetBool("json"); asJSON {
68					enc := json.NewEncoder(cmd.OutOrStdout())
69					enc.SetIndent("", "  ")
70					return enc.Encode(rec)
71				}
72				fmt.Fprintf(cmd.OutOrStdout(), "%s  %s  %d\n", rec.RunID, rec.Status, rec.ExitCode)
73				return nil
74			},
75		}
76		cmd.Flags().String("definition", "", "Execution definition ID to use when multiple generators exist")
77		cmd.Flags().Bool("json", false, "Output JSON")
78		return cmd
79	}
80	
81	func selectArtifactGenerator(store *ddxexec.Store, artifactID, explicitDefinitionID string) (string, error) {
82		if explicitDefinitionID != "" {
83			def, err := store.ShowDefinition(explicitDefinitionID)
84			if err != nil {
85				return "", err
86			}
87			if !stringSliceContains(def.ArtifactIDs, artifactID) {
88				return "", fmt.Errorf("exec definition %q does not produce artifact %q", explicitDefinitionID, artifactID)
89			}
90			return def.ID, nil
91		}
92	
93		defs, err := store.ListDefinitions(artifactID)
94		if err != nil {
95			return "", err
96		}
97		switch len(defs) {
98		case 0:
99			return "", fmt.Errorf("artifact %q has no generator definition or generated_by provenance; cannot regenerate", artifactID)
100		case 1:
101			return defs[0].ID, nil
102		default:
103			ids := make([]string, 0, len(defs))
104			for _, def := range defs {
105				ids = append(ids, def.ID)
106			}
107			return "", fmt.Errorf("artifact %q has multiple generator definitions (%s); pass --definition", artifactID, strings.Join(ids, ", "))
108		}
109	}
110	
111	func stringSliceContains(values []string, target string) bool {
112		for _, value := range values {
113			if value == target {
114				return true
115			}
116		}
117		return false
118	}
